const categoria = $('Receber Categoria').first().json.categoria || '';
const resultados = $input.first().json;

const lista = Array.isArray(resultados) ? resultados : [];

if (lista.length === 0) {
  return [{
    json: {
      resultado: `Nenhum produto encontrado na categoria "${categoria}".`,
      produtos: []
    }
  }];
}

const formatarPreco = (v) =>
  Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const linhas = lista.map((p) => {
  const disponivel = Number(p.estoque_atual || 0) > 0;
  const status = disponivel ? 'disponível' : 'sem estoque';
  const preco = formatarPreco(p.preco_atual || 0);
  const unidade = p.unidade || 'un';
  return `- ${p.nome}: ${preco}/${unidade} (${status})`;
});

return [{
  json: {
    resultado: `Produtos da categoria ${categoria}:\n` + linhas.join('\n'),
    produtos: lista.map((p) => ({
      produto_id: p.id || '',
      nome: p.nome || '',
      preco_unitario: Number(p.preco_atual || 0),
      unidade: p.unidade || 'un',
      estoque: Number(p.estoque_atual || 0)
    }))
  }
}];
